#!/usr/bin/env python3
"""
Run this script inside your Channel-estimation directory to install
the updated numpy_interpolation files.

  cd D:/PRASAD/Channel-estimation
  python install_update.py
"""
import base64, lzma, os, pathlib

FILES = {
    "numpy_interpolation/_core.py": "",
    "tests/test_numpy_interpolation.py": "",
}

for path, b64 in FILES.items():
    dest = pathlib.Path(path)
    dest.parent.mkdir(parents=True, exist_ok=True)
    content = lzma.decompress(base64.b64decode(b64))
    dest.write_bytes(content)
    print(f"  Written: {path}  ({len(content):,} bytes)")

print("\nDone. Now run:")
print("  git add numpy_interpolation/_core.py tests/test_numpy_interpolation.py")
print("  git commit -m \"Add missing interp1d kinds and fix B-spline collocation matrix\"")
print("  git push origin main")
